<?php
function route_request(): void { $p=$_GET['p']??'dashboard'; if($_SERVER['REQUEST_METHOD']==='POST') handle_post($p); if(isset($_GET['download'])) handle_download($_GET['download']); $common=['locations'=>all_locations(),'containers'=>all_containers()]; switch($p){ case 'items': render('items_list',$common+['items'=>list_items($_GET),'categories'=>db()->query('SELECT DISTINCT category FROM items WHERE category IS NOT NULL AND category<>"" ORDER BY category')->fetchAll(PDO::FETCH_COLUMN),'tags'=>db()->query('SELECT name FROM tags ORDER BY name')->fetchAll(PDO::FETCH_COLUMN)]); break; case 'item_form': render('item_form',$common+['item'=>isset($_GET['id'])?get_item((int)$_GET['id']):null]); break; case 'locations': render('locations',$common); break; case 'containers': render('containers',$common); break; case 'import': render('import',['example'=>file_exists(APP_ROOT.'/docs/example_invpatch.json')?file_get_contents(APP_ROOT.'/docs/example_invpatch.json'):'']); break; case 'export': render('export'); break; case 'audit': render('audit',['logs'=>db()->query('SELECT * FROM audit_log ORDER BY id DESC LIMIT 200')->fetchAll()]); break; case 'settings': render('settings'); break; default: render('dashboard',['stats'=>dashboard_stats()]); }}
function dashboard_stats(): array { $p=db(); return ['items'=>$p->query('SELECT COUNT(*) FROM items')->fetchColumn(),'locations'=>$p->query('SELECT COUNT(*) FROM locations')->fetchColumn(),'containers'=>$p->query('SELECT COUNT(*) FROM containers')->fetchColumn(),'top'=>$p->query('SELECT COALESCE(NULLIF(category,""),"Ohne Kategorie") category, COUNT(*) c FROM items GROUP BY category ORDER BY c DESC LIMIT 8')->fetchAll(),'recent'=>$p->query('SELECT i.*, l.code location_code FROM items i JOIN locations l ON l.id=i.location_id ORDER BY i.updated_at DESC LIMIT 8')->fetchAll(),'no_cat'=>$p->query('SELECT COUNT(*) FROM items WHERE category IS NULL OR category=""')->fetchColumn(),'no_detail'=>$p->query('SELECT COUNT(*) FROM items WHERE container_id IS NULL AND (location_detail IS NULL OR location_detail="")')->fetchColumn()]; }
function handle_post(string $p): void { require_csrf(); if($p==='save_item'){ save_item($_POST, !empty($_POST['id'])?(int)$_POST['id']:null); flash('Artikel gespeichert.'); redirect('?p=items'); } if($p==='delete_item'){ delete_item((int)$_POST['id']); flash('Artikel gelöscht.'); redirect('?p=items'); } if($p==='save_location'){ $parent=($_POST['parent_id']??'')?:null; if(!empty($_POST['id'])) db()->prepare('UPDATE locations SET code=?,name=?,area=?,parent_id=?,notes=?,updated_at=? WHERE id=?')->execute([$_POST['code'],$_POST['name'],$_POST['area'],$parent,$_POST['notes'],now(),$_POST['id']]); else db()->prepare('INSERT INTO locations(code,name,area,parent_id,notes,created_at,updated_at) VALUES(?,?,?,?,?,?,?)')->execute([$_POST['code'],$_POST['name'],$_POST['area'],$parent,$_POST['notes'],now(),now()]); flash('Ort gespeichert.'); redirect('?p=locations'); } if($p==='delete_location'){ try{ db()->prepare('DELETE FROM locations WHERE id=?')->execute([(int)$_POST['id']]); flash('Ort gelöscht.'); } catch(Throwable $e){ flash('Ort kann nicht gelöscht werden, solange Unterorte, Behälter oder Artikel daran hängen.', 'err'); } redirect('?p=locations'); } if($p==='save_container'){ if(!empty($_POST['id'])) db()->prepare('UPDATE containers SET code=?,name=?,type=?,location_id=?,notes=?,updated_at=? WHERE id=?')->execute([$_POST['code'],$_POST['name'],$_POST['type'],$_POST['location_id'],$_POST['notes'],now(),$_POST['id']]); else db()->prepare('INSERT INTO containers(code,name,type,location_id,notes,created_at,updated_at) VALUES(?,?,?,?,?,?,?)')->execute([$_POST['code'],$_POST['name'],$_POST['type'],$_POST['location_id'],$_POST['notes'],now(),now()]); flash('Behälter gespeichert.'); redirect('?p=containers'); } if($p==='import'){ $json=$_POST['json']??''; if(!empty($_FILES['file']['tmp_name'])) $json=file_get_contents($_FILES['file']['tmp_name']); $res=apply_invpatch($json, ($_POST['mode']??'preview')==='preview'); $_SESSION['import_result']=$res; $_SESSION['import_json']=$json; flash($res['errors']?'Import enthält Fehler.':(($_POST['mode']??'preview')==='preview'?'Prüfung erfolgreich.':'Import abgeschlossen.'), $res['errors']?'err':'ok'); redirect('?p=import'); } }
function handle_download(string $what): void { if($what==='full') download('kappainventar-backup.json','application/json',full_backup_json()); if($what==='invpatch') download('kappainventar-invpatch.json','application/json',invpatch_export_json()); if($what==='sqlite'){ copy(DB_PATH, DATA_DIR.'/backups/inventar-'.date('Ymd-His').'.sqlite'); header('Content-Type: application/octet-stream'); header('Content-Disposition: attachment; filename="inventar.sqlite"'); readfile(DB_PATH); exit; }}
